import{_ as a,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Vue Diff : Révision des modifications sous plusieurs angles | Plannotator","description":"Apprenez à changer le type de diff dans la revue de code Plannotator. Sélectionnez uncommitted, staged, last commit ou branch dans le menu déroulant pour réviser les modifications de code sous plusieurs angles.","frontmatter":{"title":"Vue Diff : Révision des modifications sous plusieurs angles | Plannotator","sidebarTitle":"5 types de vue diff","subtitle":"Vue Diff : Révision des modifications sous plusieurs angles","description":"Apprenez à changer le type de diff dans la revue de code Plannotator. Sélectionnez uncommitted, staged, last commit ou branch dans le menu déroulant pour réviser les modifications de code sous plusieurs angles.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"fr/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"fr/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),o={name:"fr/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function r(n,e,d,l,c,u){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="changer-la-vue-diff" tabindex="-1">Changer la vue Diff <a class="header-anchor" href="#changer-la-vue-diff" aria-label="Permalink to &quot;Changer la vue Diff&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><p>Lors de la révision de code, vous pourrez :</p><ul><li>Basculer rapidement entre 5 types de vue diff via le menu déroulant</li><li>Comprendre la portée des modifications de code affichées par chaque vue</li><li>Choisir le type de diff approprié selon vos besoins de révision</li><li>Éviter de manquer des modifications importantes en sélectionnant la mauvaise vue</li></ul><h2 id="vos-problemes-actuels" tabindex="-1">Vos problèmes actuels <a class="header-anchor" href="#vos-problemes-actuels" aria-label="Permalink to &quot;Vos problèmes actuels&quot;">​</a></h2><p><strong>Lors de la révision, vous ne regardez que la zone de travail et manquez les fichiers indexés</strong> :</p><p>Vous exécutez la commande <code>/plannotator-review</code>, voyez quelques modifications de code et ajoutez plusieurs commentaires. Mais après le commit, vous vous rendez compte que la révision a manqué les fichiers déjà <code>git add</code> dans la zone de staging — ces fichiers n&#39;apparaissent tout simplement pas dans le diff.</p><p><strong>Vous voulez voir les différences globales entre la branche actuelle et la branche main</strong> :</p><p>Vous développez sur une branche feature depuis plusieurs semaines et voulez voir tout ce qui a changé, mais la vue « Modifications non commitées » par défaut n&#39;affiche que les modifications des derniers jours.</p><p><strong>Vous voulez comparer les différences entre deux commits spécifiques</strong> :</p><p>Vous voulez vérifier qu&#39;un correctif de bug est correct et devez comparer le code avant et après la correction, mais vous ne savez pas comment faire afficher le diff des commits historiques par Plannotator.</p><h2 id="quand-utiliser-cette-technique" tabindex="-1">Quand utiliser cette technique <a class="header-anchor" href="#quand-utiliser-cette-technique" aria-label="Permalink to &quot;Quand utiliser cette technique&quot;">​</a></h2><ul><li><strong>Lors d&#39;une révision complète</strong> : Voir simultanément les modifications de la zone de travail et de la zone de staging</li><li><strong>Avant la fusion de branche</strong> : Vérifier toutes les modifications de la branche actuelle par rapport à main/master</li><li><strong>Lors d&#39;une révision de rollback</strong> : Confirmer les fichiers modifiés par le dernier commit</li><li><strong>En collaboration multi-utilisateur</strong> : Vérifier le code indexé mais non commité par les collègues</li></ul><h2 id="concept-principal" tabindex="-1">Concept principal <a class="header-anchor" href="#concept-principal" aria-label="Permalink to &quot;Concept principal&quot;">​</a></h2><p>La commande git diff a de nombreuses variantes, chacune affichant une portée de code différente. Plannotator regroupe ces variantes dans un menu déroulant unique, vous évitant de mémoriser des commandes git complexes.</p><div class="info custom-block"><p class="custom-block-title">Aide-mémoire des types de Git Diff</p><table tabindex="0"><thead><tr><th>Type de diff</th><th>Portée d&#39;affichage</th><th>Cas d&#39;utilisation typique</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>Zone de travail + Zone de staging</td><td>Réviser toutes les modifications du développement en cours</td></tr><tr><td>Staged changes</td><td>Zone de staging uniquement</td><td>Réviser le contenu préparé pour le commit avant soumission</td></tr><tr><td>Unstaged changes</td><td>Zone de travail uniquement</td><td>Réviser les modifications non encore <code>git add</code></td></tr><tr><td>Last commit</td><td>Dernier commit</td><td>Rollback ou révision du commit juste effectué</td></tr><tr><td>vs main</td><td>Branche actuelle vs branche par défaut</td><td>Vérification complète avant fusion de branche</td></tr></tbody></table></div><p>Les options du menu déroulant changent dynamiquement selon votre état Git :</p><ul><li>Si vous n&#39;êtes pas sur la branche par défaut, l&#39;option « vs main » s&#39;affiche</li><li>S&#39;il n&#39;y a pas de fichiers indexés, la vue Staged affiche « No staged changes »</li></ul><h2 id="suivez-le-guide" tabindex="-1">Suivez le guide <a class="header-anchor" href="#suivez-le-guide" aria-label="Permalink to &quot;Suivez le guide&quot;">​</a></h2><h3 id="etape-1-demarrer-la-revision-de-code" tabindex="-1">Étape 1 : Démarrer la révision de code <a class="header-anchor" href="#etape-1-demarrer-la-revision-de-code" aria-label="Permalink to &quot;Étape 1 : Démarrer la révision de code&quot;">​</a></h3><p><strong>Pourquoi</strong></p><p>Il faut d&#39;abord ouvrir l&#39;interface de révision de code de Plannotator.</p><p><strong>Action</strong></p><p>Exécutez dans le terminal :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong></p><p>Le navigateur ouvre la page de révision de code, avec un menu déroulant au-dessus de l&#39;arborescence des fichiers à gauche affichant le type de diff actuel (généralement « Uncommitted changes »).</p><h3 id="etape-2-passer-a-la-vue-staged" tabindex="-1">Étape 2 : Passer à la vue Staged <a class="header-anchor" href="#etape-2-passer-a-la-vue-staged" aria-label="Permalink to &quot;Étape 2 : Passer à la vue Staged&quot;">​</a></h3><p><strong>Pourquoi</strong></p><p>Voir les fichiers déjà <code>git add</code> mais pas encore commités.</p><p><strong>Action</strong></p><ol><li>Cliquez sur le menu déroulant au-dessus de l&#39;arborescence des fichiers à gauche</li><li>Sélectionnez « Staged changes »</li></ol><p><strong>Ce que vous devriez voir</strong></p><ul><li>S&#39;il y a des fichiers indexés, l&#39;arborescence des fichiers affiche ces fichiers</li><li>S&#39;il n&#39;y a pas de fichiers indexés, la zone principale affiche : « No staged changes. Stage some files with git add. »</li></ul><h3 id="etape-3-passer-a-la-vue-last-commit" tabindex="-1">Étape 3 : Passer à la vue Last Commit <a class="header-anchor" href="#etape-3-passer-a-la-vue-last-commit" aria-label="Permalink to &quot;Étape 3 : Passer à la vue Last Commit&quot;">​</a></h3><p><strong>Pourquoi</strong></p><p>Réviser le code que vous venez de committer pour confirmer qu&#39;il n&#39;y a pas de problème.</p><p><strong>Action</strong></p><ol><li>Rouvrez le menu déroulant</li><li>Sélectionnez « Last commit »</li></ol><p><strong>Ce que vous devriez voir</strong></p><ul><li>Affiche tous les fichiers modifiés par le dernier commit</li><li>Le contenu du diff est la différence <code>HEAD~1..HEAD</code></li></ul><h3 id="etape-4-passer-a-la-vue-vs-main-si-disponible" tabindex="-1">Étape 4 : Passer à la vue vs main (si disponible) <a class="header-anchor" href="#etape-4-passer-a-la-vue-vs-main-si-disponible" aria-label="Permalink to &quot;Étape 4 : Passer à la vue vs main (si disponible)&quot;">​</a></h3><p><strong>Pourquoi</strong></p><p>Voir toutes les modifications de la branche actuelle par rapport à la branche par défaut.</p><p><strong>Action</strong></p><ol><li>Vérifiez si l&#39;option « vs main » ou « vs master » existe dans le menu déroulant</li><li>Si oui, sélectionnez-la</li></ol><p><strong>Ce que vous devriez voir</strong></p><ul><li>L&#39;arborescence des fichiers affiche tous les fichiers différents entre la branche actuelle et la branche par défaut</li><li>Le contenu du diff est les modifications complètes <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Vérifier la branche actuelle</p><p>Si vous ne voyez pas l&#39;option « vs main », c&#39;est que vous êtes sur la branche par défaut. Vous pouvez vérifier la branche actuelle avec la commande suivante :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Passez à une branche feature et réessayez :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Confirmez que vous avez maîtrisé :</p><ul><li>[ ] Pouvoir trouver et ouvrir le menu déroulant des types de diff</li><li>[ ] Comprendre les différences entre « Uncommitted », « Staged » et « Last commit »</li><li>[ ] Pouvoir identifier quand l&#39;option « vs main » apparaît</li><li>[ ] Savoir quel type de diff utiliser dans quel scénario</li></ul><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><h3 id="piege-1-lors-de-la-revision-vous-ne-regardez-que-uncommitted-et-manquez-les-fichiers-staged" tabindex="-1">Piège 1 : Lors de la révision, vous ne regardez que Uncommitted et manquez les fichiers Staged <a class="header-anchor" href="#piege-1-lors-de-la-revision-vous-ne-regardez-que-uncommitted-et-manquez-les-fichiers-staged" aria-label="Permalink to &quot;Piège 1 : Lors de la révision, vous ne regardez que Uncommitted et manquez les fichiers Staged&quot;">​</a></h3><p><strong>Symptôme</strong></p><p>Après le commit, vous vous rendez compte que la révision a manqué certains fichiers indexés.</p><p><strong>Cause</strong></p><p>La vue Uncommitted affiche toutes les modifications de la zone de travail et de la zone de staging (<code>git diff HEAD</code>), les fichiers indexés sont également inclus.</p><p><strong>Solution</strong></p><p>Avant la révision, passez d&#39;abord à la vue Staged pour vérifier, ou utilisez la vue Uncommitted (qui inclut la zone de staging).</p><h3 id="piege-2-pas-de-comparaison-avec-main-avant-la-fusion-de-branche" tabindex="-1">Piège 2 : Pas de comparaison avec main avant la fusion de branche <a class="header-anchor" href="#piege-2-pas-de-comparaison-avec-main-avant-la-fusion-de-branche" aria-label="Permalink to &quot;Piège 2 : Pas de comparaison avec main avant la fusion de branche&quot;">​</a></h3><p><strong>Symptôme</strong></p><p>Après avoir fusionné vers main, vous découvrez des modifications non pertinentes introduites.</p><p><strong>Cause</strong></p><p>Vous n&#39;avez regardé que les commits des derniers jours, sans comparer les différences globales de la branche par rapport à main.</p><p><strong>Solution</strong></p><p>Avant la fusion, vérifiez complètement avec la vue « vs main ».</p><h3 id="piege-3-penser-que-changer-de-vue-perd-les-commentaires" tabindex="-1">Piège 3 : Penser que changer de vue perd les commentaires <a class="header-anchor" href="#piege-3-penser-que-changer-de-vue-perd-les-commentaires" aria-label="Permalink to &quot;Piège 3 : Penser que changer de vue perd les commentaires&quot;">​</a></h3><p><strong>Symptôme</strong></p><p>Vous n&#39;osez pas changer le type de diff, de peur que les commentaires précédemment ajoutés disparaissent.</p><p><strong>Cause</strong></p><p>Mauvaise compréhension du mécanisme de changement.</p><p><strong>Situation réelle</strong></p><p>Lorsque vous changez le type de diff, Plannotator conserve les commentaires précédents — ils peuvent toujours être pertinents, ou vous pouvez supprimer manuellement les commentaires non pertinents.</p><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><p>Les 5 types de diff pris en charge par Plannotator :</p><table tabindex="0"><thead><tr><th>Type</th><th>Commande Git</th><th>Scénario</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Réviser toutes les modifications du développement en cours</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Réviser la zone de staging avant commit</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Réviser les modifications de la zone de travail</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Rollback ou révision du commit le plus récent</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Vérification complète avant fusion de branche</td></tr></tbody></table><p>Changer de vue ne perd pas les commentaires, vous pouvez voir les mêmes commentaires ou de nouveaux sous différentes perspectives.</p><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../../advanced/url-sharing/">Partage par URL</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment compresser le contenu de révision dans une URL pour le partager avec des collègues</li><li>Comment le destinataire ouvre le lien de révision partagé</li><li>Les limitations et précautions en mode partage</li></ul></blockquote><hr><h2 id="annexe-references-du-code-source" tabindex="-1">Annexe : Références du code source <a class="header-anchor" href="#annexe-references-du-code-source" aria-label="Permalink to &quot;Annexe : Références du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Définition des types de Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Récupération du contexte Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Exécution de Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Traitement du changement de Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Rendu des options Diff dans l&#39;arborescence des fichiers</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Types clés</strong> :</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>getGitContext()</code>: Récupère la branche actuelle, la branche par défaut et les options de diff disponibles</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Exécute la commande git correspondante selon le type de diff</li></ul><p><strong>API clés</strong> :</p><ul><li><code>POST /api/diff/switch</code>: Change le type de diff et retourne les nouvelles données de diff</li></ul></details>',83)])])}const h=a(o,[["render",r]]);export{m as __pageData,h as default};
